declare function mapBottom(): Promise<void>;

/**
 * Map left (throws error in Dofus Retro context)
 */
declare function mapLeft(): Promise<void>;

/**
 * Map right (throws error in Dofus Retro context)
 */
declare function mapRight(): Promise<void>;

/**
 * Map top (throws error in Dofus Retro context)
 */
declare function mapTop(): Promise<void>;

/**
 * Mount your dd
 */
declare function mountDD(): Promise<void>;

/**
 * Move to a specific cell on the map
 */
declare function moveToCell(cell?: number, options?: { escapeMobs?: boolean }): Promise<boolean>;

/**
 * Move to map (throws error in Dofus Retro context)
 */
declare function moveToMap(): Promise<void>;

/**
 * Get my current cell
 */
declare function myCell(): number;

/**
 * Open your dd inventory
 */
declare function openDDInventory(): Promise<void>;

/**
 * Open merchant mode
 */
declare function openMerchantMode(): Promise<void>;

/**
 * Open a trash on the current map to dispose of unwanted items
 */
declare function openTrash(): Promise<void>;

/**
 * Open wings
 */
declare function openWings(): Promise<void>;

/**
 * Pass turn while in fight
 */
declare function passTurn(): Promise<void>;

/**
 * Equip a quick equipment set by index
 */
declare function quickEquip(id: number): Promise<void>;

/**
 * Ready while in fight
 */
declare function ready(): Promise<void>;

/**
 * Refuse an exchange invitation
 */
declare function refuseExchange(): Promise<void>;

/**
 * Refuse a fight invitation
 */
declare function refuseFight(): Promise<void>;

/**
 * Refuse an invitation to join a group
 */
declare function refuseGroupInvitation(): Promise<void>;

/**
 * Refuse an invitation to join a guild
 */
declare function refuseGuildInvitation(): Promise<void>;

/**
 * Ride your mule
 */
declare function rideMule(): Promise<void>;

/**
 * Check if the character is still on the specified map
 */
declare function sameMap(mapId: number): boolean;

/**
 * Send an invitation to exchange with someone else
 */
declare function sendExchangeInvitation(args?: { name: string }): Promise<void>;

/**
 * Send an invitation to join your group
 */
declare function sendGroupInvitation(args?: { name: string }): Promise<void>;

/**
 * Send a private message to another player
 */
declare function sendPrivateMessage(args?: { name: string; message: string }): Promise<void>;

/**
 * Store a value in the cache with the specified key
 */
declare function setCache(key: string | number, value: any): void;

/**
 * Check if someone is on the provided cell
 */
declare function someoneOnCell(cell: number): boolean;

/**
 * Speak to an NPC on the map and navigate through dialog options
 */
declare function speakToNpc(args: { id?: number; cell?: number; dialogs: number[]; dialogIds?: number[] }): Promise<boolean>;

/**
 * Cast a spell
 */
declare function spell(args: { id: number; cell?: number; t?: number; cooldown?: number; ap?: number; retry?: boolean }): Promise<void>;

/**
 * Take a prism
 */
declare function takePrism(mapId: number): Promise<void>;

/**
 * Take a zaap
 */
declare function takeZaap(mapId: number): Promise<void>;

/**
 * Take a zaapi
 */
declare function takeZaapi(mapId: number): Promise<void>;

/**
 * Transfer items from your dragoturkey (DD) inventory to your character inventory
 */
declare function transferDDToInventory(args?: { objects?: Record<string, number> }): Promise<void>;

/**
 * Transfer items from bank to your inventory
 */
declare function transferFromBankToInventory(args: { objects: Record<string, number | "all">; kamas?: number }): Promise<void>;

/**
 * Transfer items from dd to your inventory
 */
declare function transferFromDDToInventory(args: { objects: Record<string, number> }): Promise<void>;

/**
 * Transfer items from your inventory to your merchant shop for sale
 */
declare function transferFromInventoryToMerchantShop(args?: { objects?: Array<number | string>; price?: number; prices?: Record<string, number> }): Promise<void>;

/**
 * Transfer items from merchant shop to your inventory
 */
declare function transferFromMerchantShopToInventory(args?: { objects?: Array<number | string>; price?: number; prices?: Record<string, number> }): Promise<void>;

/**
 * Transfer items from your inventory to the bank
 */
declare function transferInventoryToBank(args: { objects?: Record<string, number>; skip?: number[]; skipCategories?: string[]; categories?: string[]; types?: number[]; kamas?: number }): Promise<void>;

/**
 * Transfer items from your inventory to DD
 */
declare function transferInventoryToDD(args: { objects?: Record<string, number>; skip?: number[] }): Promise<void>;

/**
 * Transfer items from your inventory to the exchange
 */
declare function transferInventoryToExchange(args: { objects?: Record<string, number>; skip?: number[]; kamas?: number }): Promise<void>;

/**
 * Transfer items from your inventory to the trash
 */
declare function transferInventoryToTrash(args?: { objects?: Array<number | string>; skip?: number[] }): Promise<void>;

/**
 * Transfer kamas between inventory and bank
 */
declare function transferKamas(args: { kamas: number; from: "inventory" | "bank"; to: "inventory" | "bank" }): Promise<void>;

/**
 * Travel (throws error in Dofus Retro context)
 */
