/**
 * Use an object from inventory
 */
declare function useObject(args: { id: number; quantity?: number; max?: boolean }): Promise<boolean>;

/**
 * Validate an exchange
 */
declare function validateExchange(): Promise<void>;

/**
 * Wait for all group members to be present on the current map before proceeding
 */
declare function waitGroup(): Promise<void>;

